import{_ as t,a,b as o,c as l}from"./chunks/授权完复制token.D-mju0qq.js";import{_ as i,o as n,c as s,a2 as r}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"افزودن Google Drive Channel","description":"","frontmatter":{},"headers":[],"relativePath":"fa/upload/google-drive.md","filePath":"fa/upload/google-drive.md","lastUpdated":1781962217000}'),d={name:"fa/upload/google-drive.md"};function c(p,e,h,g,u,m){return n(),s("div",null,[...e[0]||(e[0]=[r('<h1 id="افزودن-google-drive-channel" tabindex="-1">افزودن Google Drive Channel <a class="header-anchor" href="#افزودن-google-drive-channel" aria-label="Permalink to &quot;افزودن Google Drive Channel&quot;">​</a></h1><h2 id="ابتدا-چه-چیزهایی-لازم-است" tabindex="-1">ابتدا چه چیزهایی لازم است <a class="header-anchor" href="#ابتدا-چه-چیزهایی-لازم-است" aria-label="Permalink to &quot;ابتدا چه چیزهایی لازم است&quot;">​</a></h2><table tabindex="0"><thead><tr><th>مورد</th><th>چرا لازم است</th></tr></thead><tbody><tr><td>Google account</td><td>برای دسترسی به Google Cloud و authorize کردن Google Drive</td></tr><tr><td>Google Cloud project</td><td>برای enable کردن Drive API و ساخت OAuth credentials</td></tr><tr><td>OAuth 2.0 client</td><td>برای گرفتن <code>Client ID</code>، <code>Client Secret</code> و <code>Refresh Token</code> توسط ImgBed</td></tr><tr><td>دامنه ImgBed شما</td><td>برای OAuth redirect URI. باید دقیقاً با دامنه‌ای که واقعاً استفاده می‌کنید match باشد.</td></tr></tbody></table><h2 id="مراحل-setup" tabindex="-1">مراحل setup <a class="header-anchor" href="#مراحل-setup" aria-label="Permalink to &quot;مراحل setup&quot;">​</a></h2><h3 id="step-1-enable-کردن-google-drive-api" tabindex="-1">Step 1: Enable کردن Google Drive API <a class="header-anchor" href="#step-1-enable-کردن-google-drive-api" aria-label="Permalink to &quot;Step 1: Enable کردن Google Drive API&quot;">​</a></h3><ol><li>Google Cloud Console را باز کنید.</li><li>یک project جدید بسازید یا project موجود را انتخاب کنید.</li><li>به <code>APIs &amp; Services</code> بروید.</li><li><code>Enable APIs and Services</code> را بزنید.</li><li><code>Google Drive API</code> را جست‌وجو کنید.</li><li>آن را باز کنید و enable را بزنید.</li></ol><h3 id="step-2-configure-کردن-oauth-consent-screen" tabindex="-1">Step 2: Configure کردن OAuth Consent Screen <a class="header-anchor" href="#step-2-configure-کردن-oauth-consent-screen" aria-label="Permalink to &quot;Step 2: Configure کردن OAuth Consent Screen&quot;">​</a></h3><ol><li>در Google Cloud، <code>Google Auth Platform</code> را باز کنید.</li><li>اطلاعات پایه <code>Branding</code> مثل app name، support email و developer contact email را کامل کنید.</li><li><code>Audience</code> را باز کنید.</li><li>برای بیشتر self-hosted personal deployments، <code>External</code> را انتخاب کنید.</li><li>اگر <code>External</code> انتخاب کردید، Google account موردنظر برای authorization را در <code>Test users</code> اضافه کنید.</li><li><code>Data Access</code> را باز کنید.</li><li>permissions موردنیاز Google Drive را اضافه کنید.</li></ol><h3 id="step-3-ساخت-oauth-2-0-client" tabindex="-1">Step 3: ساخت OAuth 2.0 Client <a class="header-anchor" href="#step-3-ساخت-oauth-2-0-client" aria-label="Permalink to &quot;Step 3: ساخت OAuth 2.0 Client&quot;">​</a></h3><ol><li>در <code>Google Auth Platform</code>، <code>Clients</code> را باز کنید.</li><li>یک client جدید بسازید.</li><li>application type را <code>Web application</code> بگذارید.</li><li>یک نام قابل‌تشخیص برای client وارد کنید.</li><li>برای authorized JavaScript origins، URL ImgBed را وارد کنید، مثلاً:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://img.example.com</span></span></code></pre></div><ol start="6"><li>برای authorized redirect URIs وارد کنید:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://img.example.com/api/oauth/google/callback</span></span></code></pre></div><p><img src="'+t+'" alt="Create OAuth client" loading="lazy"></p><p><img src="'+a+'" alt="Enter domain and callback URL" loading="lazy"></p><p>پس از ساخت client، این values را copy کنید:</p><table tabindex="0"><thead><tr><th>Generated Value</th><th>ImgBed Field</th></tr></thead><tbody><tr><td>Client ID</td><td><code>Client ID</code></td></tr><tr><td>Client Secret</td><td><code>Client Secret</code></td></tr></tbody></table><h2 id="step-4-پر-کردن-google-drive-channel-در-imgbed" tabindex="-1">Step 4: پر کردن Google Drive Channel در ImgBed <a class="header-anchor" href="#step-4-پر-کردن-google-drive-channel-در-imgbed" aria-label="Permalink to &quot;Step 4: پر کردن Google Drive Channel در ImgBed&quot;">​</a></h2><p>در Upload Settings، <code>Google Drive</code> را انتخاب کنید و پر کنید:</p><table tabindex="0"><thead><tr><th>ImgBed Field</th><th>What To Enter</th></tr></thead><tbody><tr><td>Channel name</td><td>نام قابل‌تشخیص، مثل <code>Main Google Drive</code></td></tr><tr><td>Client ID</td><td>Client ID از Google Cloud</td></tr><tr><td>Client Secret</td><td>Client Secret از Google Cloud</td></tr><tr><td>Refresh Token</td><td>فعلاً خالی بگذارید. در step بعدی می‌گیرید.</td></tr><tr><td>Root directory</td><td>اختیاری. پیش‌فرض <code>imgbed</code>.</td></tr></tbody></table><p><img src="'+o+'" alt="Fill client details in ImgBed" loading="lazy"></p><h2 id="step-5-گرفتن-refresh-token" tabindex="-1">Step 5: گرفتن Refresh Token <a class="header-anchor" href="#step-5-گرفتن-refresh-token" aria-label="Permalink to &quot;Step 5: گرفتن Refresh Token&quot;">​</a></h2><ol><li><code>Get Token</code> را بزنید.</li><li>Google account موردنظر برای اتصال را انتخاب کنید.</li><li>authorization prompts را کامل کنید.</li><li>callback page یک <code>Refresh Token</code> نشان می‌دهد.</li><li>آن را copy کنید.</li><li>به ImgBed برگردید و در <code>Refresh Token</code> paste کنید.</li></ol><p><img src="'+l+`" alt="Copy Refresh Token after authorization" loading="lazy"></p><p>اگر بعداً Google account را عوض کردید، OAuth client را تغییر دادید، یا authorization قبلی expire شد، لازم نیست channel را delete کنید. edit page را باز کنید و <code>Reauthorize</code> را بزنید.</p><h2 id="step-6-save-کردن-channel" tabindex="-1">Step 6: Save کردن Channel <a class="header-anchor" href="#step-6-save-کردن-channel" aria-label="Permalink to &quot;Step 6: Save کردن Channel&quot;">​</a></h2><p>پس از پر کردن همه fields، channel را save کنید.</p><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Google Cloud را باز کنید</span></span>
<span class="line"><span>-&gt; project بسازید یا انتخاب کنید</span></span>
<span class="line"><span>-&gt; Google Drive API را enable کنید</span></span>
<span class="line"><span>-&gt; Google Auth Platform را configure کنید</span></span>
<span class="line"><span>-&gt; اگر Audience برابر External است، Google account را به Test users اضافه کنید</span></span>
<span class="line"><span>-&gt; Web application OAuth client بسازید</span></span>
<span class="line"><span>-&gt; https://your-domain.com/api/oauth/google/callback را به‌عنوان redirect URI بگذارید</span></span>
<span class="line"><span>-&gt; Client ID و Client Secret را در ImgBed وارد کنید</span></span>
<span class="line"><span>-&gt; Get Token را بزنید</span></span>
<span class="line"><span>-&gt; با Google sign in و authorize کنید</span></span>
<span class="line"><span>-&gt; Refresh Token را از callback page copy کنید</span></span>
<span class="line"><span>-&gt; در ImgBed paste و save کنید</span></span>
<span class="line"><span>-&gt; test image upload کنید</span></span></code></pre></div><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ol><li>Google OAuth Web Server Applications: <a href="https://developers.google.com/identity/protocols/oauth2/web-server" target="_blank" rel="noreferrer">https://developers.google.com/identity/protocols/oauth2/web-server</a></li><li>Google Workspace OAuth Consent Configuration: <a href="https://developers.google.com/workspace/guides/configure-oauth-consent" target="_blank" rel="noreferrer">https://developers.google.com/workspace/guides/configure-oauth-consent</a></li><li>Google Drive API Auth Scopes: <a href="https://developers.google.com/workspace/drive/api/guides/api-specific-auth" target="_blank" rel="noreferrer">https://developers.google.com/workspace/drive/api/guides/api-specific-auth</a></li></ol>`,31)])])}const k=i(d,[["render",c]]);export{f as __pageData,k as default};
